import "mx-global";
import { Big } from "big.js";

// BEGIN EXTRA CODE
function isValidInteger(input) {
    const regex = /^-?\d{1,10}$/;
    if (!regex.test(input)) {
        return false;
    }
    const number = Number(input);
    return Number.isInteger(number);
}

function isValidLong(input) {
    const regex = /^-?\d{1,19}$/;
    if (!regex.test(input)) {
        return false;
    }
    try {
        const bigInt = Big(input);
        return true;
    } catch (e) {
        return false;
    }
}
// END EXTRA CODE

/**
 * @param {string} fieldRef
 * @param {string} objectGUID
 * @param {string} scannedString
 * @param {boolean} [allowDuplicateValue]
 * @returns {Promise.<string>}
 */
export async function JS_ModifyObjectAttribute(fieldRef, objectGUID, scannedString, allowDuplicateValue) {
	// BEGIN USER CODE
	return new Promise(function(resolve, reject) {
		mx.data.get({
			guid: objectGUID,
			callback: function(obj) {
				//console.info("Received MxObject with GUID " + obj.getGuid());
				if (obj.isNumeric(fieldRef)) {
					if (isNaN(scannedString)){
						resolve("invalidData");
						return;
					} else if (obj.getAttributeType(fieldRef) === "Integer"){
						if (!isValidInteger(scannedString)){
							resolve("invalidData");
							return;
						}
					} else if (obj.getAttributeType(fieldRef) === "Long"){
						if (!isValidLong(scannedString)){
							resolve("invalidData");
							return;
						}
					}
				}				
				if(obj.get(fieldRef) === scannedString && !allowDuplicateValue){
					resolve("unmodified");
					return;
				}
				obj.set(fieldRef, scannedString);
				mx.data.commit({
					mxobj: obj, 
					callback: function(commitedObj) {
        				//console.info("Object committed");
						resolve("committed");
    				},
    				error: function(e) {
        				console.warn("Could not commit object:", e);
						resolve("Error");
    				}
				});
    		},
			error: function(e) {
        		console.warn("Could not retrieve MxObject with GUID " + obj.getGuid() + " " , e);
				resolve("Error");
    		}
		});	
	});
	// END USER CODE
}
